import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import P2PExchangeScreen from "@screens/p2p-exchange-development";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const P2PExchangeDevelopment = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "P2P Crypto Exchange Development Company", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.p2pCryptoImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Build a secure peer-to-peer crypto exchange that enables direct trading, escrow protection, fast transactions, and full user control.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1605",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is P2P in crypto?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "P2P crypto allows users to trade digital assets directly with each other, without intermediaries, using secure platforms with escrow protection.",
            },
          },
          {
            "@type": "Question",
            name: "Which platform is best for P2P?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Binance P2P is a top platform for secure, direct crypto trading with escrow protection and multiple payment options.",
            },
          },
          {
            "@type": "Question",
            name: "Which wallet is best for P2P?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "MetaMask is one of the best wallets for P2P crypto trading because it’s widely supported, secure, and easy to connect with DEX and P2P platforms.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <P2PExchangeScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default P2PExchangeDevelopment;

export const queryData = graphql`
  query myQuery {
    p2pCryptoImg: file(relativePath: { eq: "p2p-crypto.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "p2p-crypto-exchange-development" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
